	name: "GTAOBlendShader",
	uniforms: {
		tDiffuse: { value: null },
		intensity: { value: 1 }
	},
	vertexShader: `
		varying vec2 vUv;

		void main() {
			vUv = uv;
			gl_Position = projectionMatrix * modelViewMatrix * vec4( position, 1.0 );
		}`,
