		"tDiffuse": { value: null },
		"tNormal": { value: null },
		"tDepth": { value: null },
		"tNoise": { value: null },
		"resolution": { value: new Vector2() },
		"cameraProjectionMatrixInverse": { value: new Matrix4() },
